import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { EventBus } from '../../src/events/event-bus.js';
import { UserService, resetUserIdCounter } from '../../src/services/user.service.js';
import { OrderService, resetOrderIdCounter } from '../../src/services/order.service.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import { paginate } from '../../src/utils/pagination.js';
import type { OrderItem } from '../../src/models/order.js';

/**
 * Integration tests for the full pipeline:
 * UserService + OrderService + NotificationService + EventBus + CallbackRegistry + Database
 *
 * These tests wire up the entire stack without mocks and verify end-to-end behavior.
 */
describe('Full Pipeline Integration', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let eventBus: EventBus;
  let userService: UserService;
  let orderService: OrderService;
  let notificationService: NotificationService;

  const sampleItems: OrderItem[] = [
    { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10.0 },
    { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25.5 },
  ];

  beforeEach(() => {
    // Fresh database and event system for each test
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    eventBus = new EventBus();
    statusChangeCallbacks.clear();

    // Reset ID counters
    resetUserIdCounter();
    resetOrderIdCounter();
    resetNotificationIdCounter();

    // Wire up services — NotificationService subscribes to EventBus and CallbackRegistry in constructor
    userService = new UserService(userRepo, eventBus);
    orderService = new OrderService(orderRepo, userRepo, eventBus);
    notificationService = new NotificationService(eventBus);
  });

  describe('User creation through event pipeline', () => {
    it('should create a user and emit user:created event', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'admin',
      });

      expect(user.id).toBe('user-0001');
      expect(user.name).toBe('Alice');
      expect(user.role).toBe('admin');

      // Verify event was logged
      const events = eventBus.getEventLog();
      expect(events).toHaveLength(1);
      expect(events[0]!.type).toBe('user:created');

      // Verify user is persisted and retrievable
      const found = userService.getUser(user.id);
      expect(found).toBeDefined();
      expect(found!.email).toBe('alice@example.com');
    });

    it('should create multiple users with sequential IDs', async () => {
      const alice = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'admin' });
      const bob = await userService.createUser({ name: 'Bob', email: 'bob@example.com', role: 'member' });

      expect(alice.id).toBe('user-0001');
      expect(bob.id).toBe('user-0002');

      const allUsers = userService.listUsers();
      expect(allUsers).toHaveLength(2);
    });
  });

  describe('Order creation with notification pipeline', () => {
    it('should create an order and generate a notification via EventBus', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      const order = await orderService.createOrder({
        userId: user.id,
        items: sampleItems,
      });

      expect(order.id).toBe('order-0001');
      expect(order.total).toBe(45.5); // 2*10 + 1*25.5
      expect(order.status).toBe('pending');

      // Verify notification was generated through EventBus pipeline
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);

      const notif = notifications[0]!;
      expect(notif.recipient).toBe('alice@example.com');
      expect(notif.subject).toContain('Order Confirmation');
      expect(notif.subject).toContain(order.id);
      expect(notif.body).toContain('Widget x2');
      expect(notif.body).toContain('Gadget x1');
      expect(notif.body).toContain('$45.50');
    });

    it('should generate notifications for multiple orders', async () => {
      const alice = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });
      const bob = await userService.createUser({ name: 'Bob', email: 'bob@example.com', role: 'member' });

      await orderService.createOrder({
        userId: alice.id,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });
      await orderService.createOrder({
        userId: bob.id,
        items: [{ productId: 'p2', name: 'Gadget', quantity: 3, unitPrice: 15 }],
      });

      expect(notificationService.getNotificationCount()).toBe(2);

      const aliceNotifs = notificationService.getNotificationsForRecipient('alice@example.com');
      expect(aliceNotifs).toHaveLength(1);

      const bobNotifs = notificationService.getNotificationsForRecipient('bob@example.com');
      expect(bobNotifs).toHaveLength(1);
      expect(bobNotifs[0]!.body).toContain('$45.00');
    });
  });

  describe('Order status change with notification pipeline', () => {
    it('should notify on status change via CallbackRegistry', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });
      const order = await orderService.createOrder({
        userId: user.id,
        items: sampleItems,
      });

      // 1 notification from order creation
      expect(notificationService.getNotificationCount()).toBe(1);

      await orderService.updateOrderStatus(order.id, 'confirmed');

      // 2 notifications: creation + status change
      expect(notificationService.getNotificationCount()).toBe(2);

      const notifications = notificationService.getNotifications();
      const statusNotif = notifications[1]!;
      expect(statusNotif.subject).toContain('Order Update');
      expect(statusNotif.body).toContain('pending');
      expect(statusNotif.body).toContain('confirmed');
      // Status change uses userId as recipient (not email) — this is the existing behavior
      expect(statusNotif.recipient).toBe(user.id);
    });

    it('should track full order lifecycle with notifications', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });
      const order = await orderService.createOrder({
        userId: user.id,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 100 }],
      });

      await orderService.updateOrderStatus(order.id, 'confirmed');
      await orderService.updateOrderStatus(order.id, 'shipped');
      await orderService.updateOrderStatus(order.id, 'delivered');

      // 1 creation + 3 status changes = 4 notifications
      expect(notificationService.getNotificationCount()).toBe(4);

      // Verify final order state
      const finalOrder = orderService.getOrder(order.id);
      expect(finalOrder!.status).toBe('delivered');

      // Verify event log only has creation event (status changes go through CallbackRegistry)
      const events = eventBus.getEventLog();
      const orderEvents = events.filter((e) => e.type === 'order:created');
      expect(orderEvents).toHaveLength(1);
    });
  });

  describe('Error scenarios', () => {
    it('should reject order for non-existent user', async () => {
      await expect(
        orderService.createOrder({
          userId: 'nonexistent',
          items: sampleItems,
        }),
      ).rejects.toThrow('User not found: nonexistent');
    });

    it('should reject order with empty items', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });

      await expect(
        orderService.createOrder({ userId: user.id, items: [] }),
      ).rejects.toThrow('at least one item');
    });

    it('should reject duplicate user email', async () => {
      await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });

      await expect(
        userService.createUser({ name: 'Alice 2', email: 'alice@example.com', role: 'viewer' }),
      ).rejects.toThrow('already exists');
    });

    it('should reject invalid status transition', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });
      const order = await orderService.createOrder({
        userId: user.id,
        items: sampleItems,
      });

      // Cannot go from pending directly to delivered
      await expect(
        orderService.updateOrderStatus(order.id, 'delivered'),
      ).rejects.toThrow('Invalid status transition: pending -> delivered');
    });

    it('should reject status change on non-existent order', async () => {
      await expect(
        orderService.updateOrderStatus('order-9999', 'confirmed'),
      ).rejects.toThrow('Order not found');
    });

    it('should reject transitions from terminal states', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });
      const order = await orderService.createOrder({
        userId: user.id,
        items: sampleItems,
      });

      await orderService.updateOrderStatus(order.id, 'cancelled');

      await expect(
        orderService.updateOrderStatus(order.id, 'confirmed'),
      ).rejects.toThrow('Invalid status transition: cancelled -> confirmed');
    });

    it('should not generate notifications on failed order creation', async () => {
      try {
        await orderService.createOrder({ userId: 'no-user', items: sampleItems });
      } catch {
        // expected
      }

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should reject update for non-existent user', async () => {
      await expect(
        userService.updateUser('nonexistent', { name: 'New Name' }),
      ).rejects.toThrow('User not found');
    });
  });

  describe('Cross-service data consistency', () => {
    it('should maintain data integrity across repositories sharing the same database', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });

      await orderService.createOrder({
        userId: user.id,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });
      await orderService.createOrder({
        userId: user.id,
        items: [{ productId: 'p2', name: 'Gadget', quantity: 2, unitPrice: 20 }],
      });

      // User's orders should be queryable
      const userOrders = orderService.listUserOrders(user.id);
      expect(userOrders).toHaveLength(2);

      // User data should still be intact
      const foundUser = userService.getUser(user.id);
      expect(foundUser!.name).toBe('Alice');

      // Database counts should reflect reality
      expect(userRepo.count()).toBe(1);
      expect(orderRepo.count()).toBe(2);
    });

    it('should persist order updates through repository layer', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });
      const order = await orderService.createOrder({
        userId: user.id,
        items: sampleItems,
      });

      await orderService.updateOrderStatus(order.id, 'confirmed');

      // Verify the update persisted through to the database
      const retrieved = orderService.getOrder(order.id);
      expect(retrieved!.status).toBe('confirmed');
      expect(retrieved!.updatedAt.getTime()).toBeGreaterThanOrEqual(order.updatedAt.getTime());
    });

    it('should handle user update events flowing through the pipeline', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });

      const updated = await userService.updateUser(user.id, { role: 'admin' });
      expect(updated.role).toBe('admin');

      // user:created + user:updated events
      const events = eventBus.getEventLog();
      expect(events).toHaveLength(2);
      expect(events[0]!.type).toBe('user:created');
      expect(events[1]!.type).toBe('user:updated');
    });

    it('should filter orders by status across multiple users', async () => {
      const alice = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });
      const bob = await userService.createUser({ name: 'Bob', email: 'bob@example.com', role: 'member' });

      const o1 = await orderService.createOrder({
        userId: alice.id,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });
      const o2 = await orderService.createOrder({
        userId: bob.id,
        items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 20 }],
      });
      await orderService.createOrder({
        userId: alice.id,
        items: [{ productId: 'p3', name: 'Doohickey', quantity: 1, unitPrice: 30 }],
      });

      await orderService.updateOrderStatus(o1.id, 'confirmed');
      await orderService.updateOrderStatus(o2.id, 'confirmed');

      const pending = orderService.listOrdersByStatus('pending');
      expect(pending).toHaveLength(1);

      const confirmed = orderService.listOrdersByStatus('confirmed');
      expect(confirmed).toHaveLength(2);
    });
  });

  describe('Pagination integration', () => {
    it('should paginate user lists', async () => {
      for (let i = 0; i < 5; i++) {
        await userService.createUser({
          name: `User ${i}`,
          email: `user${i}@example.com`,
          role: 'member',
        });
      }

      const allUsers = userService.listUsers();
      const page1 = paginate(allUsers, 1, 2);

      expect(page1.items).toHaveLength(2);
      expect(page1.totalItems).toBe(5);
      expect(page1.totalPages).toBe(3);
      expect(page1.hasNext).toBe(true);
      expect(page1.hasPrevious).toBe(false);
    });

    it('should paginate order lists', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });

      for (let i = 0; i < 4; i++) {
        await orderService.createOrder({
          userId: user.id,
          items: [{ productId: `p${i}`, name: `Product ${i}`, quantity: 1, unitPrice: 10 * (i + 1) }],
        });
      }

      const orders = orderService.listUserOrders(user.id);
      const page1 = paginate(orders, 1, 2);
      expect(page1.items).toHaveLength(2);
      expect(page1.hasNext).toBe(true);
    });
  });

  describe('Event log integrity', () => {
    it('should maintain complete event log across operations', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });
      await userService.updateUser(user.id, { name: 'Alice Updated' });

      const order = await orderService.createOrder({
        userId: user.id,
        items: sampleItems,
      });
      await orderService.updateOrderStatus(order.id, 'confirmed');

      const events = eventBus.getEventLog();
      // user:created, user:updated, order:created (status change goes through CallbackRegistry)
      expect(events).toHaveLength(3);
      expect(events.map((e) => e.type)).toEqual([
        'user:created',
        'user:updated',
        'order:created',
      ]);
    });

    it('should not emit user:updated event when no fields change', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });

      // Update with same values — should not emit event
      await userService.updateUser(user.id, { name: 'Alice' });

      const events = eventBus.getEventLog();
      expect(events).toHaveLength(1); // only user:created
    });
  });

  describe('User deletion impact', () => {
    it('should delete user while orders remain in database', async () => {
      const user = await userService.createUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });

      await orderService.createOrder({
        userId: user.id,
        items: sampleItems,
      });

      const deleted = userService.deleteUser(user.id);
      expect(deleted).toBe(true);
      expect(userService.getUser(user.id)).toBeUndefined();

      // Orders are still in the database (no cascade)
      const orders = orderService.listUserOrders(user.id);
      expect(orders).toHaveLength(1);
    });
  });

  describe('Role-based user filtering', () => {
    it('should filter users by role across the full pipeline', async () => {
      await userService.createUser({ name: 'Admin', email: 'admin@example.com', role: 'admin' });
      await userService.createUser({ name: 'Member 1', email: 'member1@example.com', role: 'member' });
      await userService.createUser({ name: 'Member 2', email: 'member2@example.com', role: 'member' });
      await userService.createUser({ name: 'Viewer', email: 'viewer@example.com', role: 'viewer' });

      expect(userService.listUsers('admin')).toHaveLength(1);
      expect(userService.listUsers('member')).toHaveLength(2);
      expect(userService.listUsers('viewer')).toHaveLength(1);
      expect(userService.listUsers()).toHaveLength(4);
    });
  });
});

